import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"光之剑·超新星","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/4.A级/光之剑·超新星.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/4.A级/光之剑·超新星.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/4.A级/光之剑·超新星.md"};function _(p,r,l,b,i,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"光之剑·超新星",tabindex:"-1"},[s("光之剑·超新星 "),e("a",{class:"header-anchor",href:"#光之剑·超新星","aria-label":'Permalink to "光之剑·超新星"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004B")])])],-1),o('<h1 id="光之剑·超新星-1" tabindex="-1">光之剑·超新星 <a class="header-anchor" href="#光之剑·超新星-1" aria-label="Permalink to &quot;光之剑·超新星&quot;">​</a></h1><p>光之剑·超新星<br> 科技本质<br> A+8000<br> 原本是千年工程部自主研发的一台宇宙战舰上的舰炮，后因经费不足而被迫搁置，舰炮被天童爱丽丝作为武器带走。<br> 因为武器的重量和输出功率、以至于普通人类甚至连随身携带都很困难。<br> 这是一柄体积8，炮管前端为白色，带着蓝色中端呼吸灯，并在末端加装了握把和提手的电磁炮。<br> 光之剑·超新星的武器伤害为25L，射程200米，并具有【能量武器】【湮灭】和2点附加成功。<br> 使用光之剑·超新星进行攻击需以敏捷+射击+专业：光之剑+辅助专业：能量爆发（专注）进行检定。<br> 使用光之剑·超新星进行攻击会消耗它自身携带的能量，使用光之剑·超新星的附带的技能也会消耗能量，一份能量足够支撑20次发射（换言之，储存了20点能量），在那之后，必须注入一份能量才能继续使用。<br> 一份能量的价格为10分，也可以向其中注入魔力以代替能量，需消耗5点魔力才能充满能量。<br> 为光之剑·超新星注入能量是一个整轮动作。<br> 在持有光之剑·超新星进行攻击时，还会获得以下能力：</p><p>①光啊！<br> 在某个战斗场景中，每经过三轮，便会自动触发一次本效果。令下一次【湮灭】的判定难度降低至三分之一，若下一次攻击未触发湮灭，则这个效果将保留至触发为止。</p><p>②这是强化魔法！<br> 每回合一次，在未应用【世界的法则即将崩坏!】的攻击中可以使用，消耗1点能量，此次攻击额外获得等同于使用者决心附加成功*1点附加成功，并为光之剑·超新星提供2层充能。</p><p>③世界的法则即将崩坏!<br> 一场景只能使用一次，这是一个攻击技，以一个整轮动作使用，消耗10点能量以使用此攻击技。向直线方向发射一道巨型激光，视同具有超级贯穿一般对光之剑·超新星基础射程3倍，宽度30米内的直线距离内所有敌人进行一次攻击，强韧豁免，并受到二者差值的恶性伤害，同时消耗所有充能，若消耗了至少5层充能，就将本次攻击的伤害出目提升0.5倍，并移除所有充能。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(d,[["render",_]]);export{f as __pageData,m as default};
